import{_ as t,o as n,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"11. Incidence And Operation Of This Agreement","description":"","frontmatter":{"title":"11. Incidence And Operation Of This Agreement","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/preliminary/11-incidence-and-operation-of-this-agreement.md","filePath":"ebas/mental-health/common-terms/preliminary/11-incidence-and-operation-of-this-agreement.md"}'),r={name:"ebas/mental-health/common-terms/preliminary/11-incidence-and-operation-of-this-agreement.md"};function i(s,e,c,l,d,m){return n(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_11-incidence-and-operation-of-this-agreement" tabindex="-1">11. Incidence And Operation Of This Agreement <a class="header-anchor" href="#_11-incidence-and-operation-of-this-agreement" aria-label="Permalink to &quot;11. Incidence And Operation Of This Agreement&quot;">​</a></h1><p><strong>11.1</strong> This Agreement will not apply to persons employed under the Public Administration Act 2004, (as amended or replaced from time to time), and/or any person who is an Employee of the Department and whose services have been made available to an Employer under section 97 of the Mental Health Act 1986 (Vic) (as amended or replaced from time to time) (Section 97 Employees).</p><p><strong>11.2</strong> This Agreement will operate seven days after the date on which it is approved by the Commission.</p><p><strong>11.3</strong> The Nominal Expiry Date of this Agreement is 30 December 2028. The Agreement will continue in force after the expiry date until replaced by a further enterprise agreement.</p><p><strong>11.4</strong> The VHIA on behalf of the Employer and the Unions on behalf of the Employees have created a protocol to assist Employers to collate an accurate list of eligible Employees for use in accordance with ballot processes outlined in the Fair Work Act. This protocol will be relied upon by any party with respect to any future Protection Action Ballot application.</p><p><strong>11.5</strong> The Schedules to this Agreement form part of this Agreement and are to be read in conjunction with it.</p><p><strong>11.6</strong> For the avoidance of doubt, the NES prevails to the extent that any aspect of this Agreement would otherwise be detrimental to an Employee.</p><p><strong>11.7</strong> Where clauses in this Agreement have been rewritten and/or relocated and there is a dispute about an entitlement under this Agreement, including the intent or meaning, in interpreting those clauses regard shall be given to all the antecedent relevant documents and decisions arising from them. However, the parties do not intend to incorporate into this Agreement any such documents and decisions.</p>',8)])])}const g=t(r,[["render",i]]);export{h as __pageData,g as default};
